#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld",&N,&K);
        int used[20001]={0};
        int ans[1000]; int sz=0; long long sum=0; int cur=1;
        while(sz<N && cur<=20000){
            if(sum + cur < K){
                ans[sz++]=cur; used[cur]=1; sum+=cur; cur++;
            }else break;
        }
        int big=20000;
        while(sz<N){
            if(!used[big] && big!=K){ ans[sz++]=big; used[big]=1; }
            big--;
        }
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d",ans[i]);
        }
        printf("\n");
    }
    return 0;
}

