        vector<char> used(20001,0);
        long long sum=0; int cur=1;
        while((int)ans.size()<N && cur<=20000){
            if(sum + cur < K){
                ans.push_back(cur); used[cur]=1; sum+=cur; ++cur;
            }else break;
        }
        for(int big=20000; (int)ans.size()<N; --big){
            if(!used[big] && big!=K){ ans.push_back(big); used[big]=1; }
        }
        for(int i=0;i<N;i++){
            if(i) cout<<' ';
            cout<<ans[i];
        }
        cout<<'\n';
    }
    return 0;
}

