#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        used = [False]*20001
        ans = []
        cur = 1
        total = 0
        while len(ans) < N and cur <= 20000:
            if total + cur < K:
                ans.append(cur)
                used[cur] = True
                total += cur
                cur += 1
            else:
                break
        big = 20000
        while len(ans) < N:
            if not used[big] and big != K:
                ans.append(big)
                used[big] = True
            big -= 1
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

